import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';

const SearchResults = () => {
  const [allTours, setAllTours] = useState([]);  // 🔥 ВСЕ туры
  const [tours, setTours] = useState([]);       // 🔥 ФИЛЬТРОВАННЫЕ
  const [loading, setLoading] = useState(true);
  const [searchParams] = useSearchParams();

  // 🔥 ПРАВИЛЬНАЯ ФИЛЬТРАЦИЯ
  const filterTours = (allTours) => {
    let filtered = [...allTours];

    const decodeParam = (param) => decodeURIComponent(param || '');

    // 1. Фильтр по стране ✅ РАБОТАЕТ
    const country = decodeParam(searchParams.get('country'));
    if (country) {
      console.log('🔍 Страна:', country);
      filtered = filtered.filter(tour => tour.country === country);
    }

    // 2. Фильтр по вылету ✅ РАБОТАЕТ  
    const departure = decodeParam(searchParams.get('departure'));
    if (departure) {
      console.log('🔍 Вылет:', departure);
      filtered = filtered.filter(tour => tour.departureCity === departure);
    }

    // 3. ✅ ИСПРАВЛЕННАЯ ЛОГИКА НОЧЕЙ
    const nights = decodeParam(searchParams.get('nights'));
    if (nights) {
      console.log('🔍 Ночи:', nights);
      const [minNights, maxNights] = nights.split(' - ').map(n => parseInt(n.trim()));
      
      filtered = filtered.filter(tour => {
        // Парсим nights тура: "6-14" → [6, 14]
        const tourNights = tour.nights.split('-').map(n => parseInt(n.trim()));
        
        // ✅ НОВЫЕ ПРАВИЛА:
        // Диапазон тура [6-14] попадает в фильтр [8-14] если:
        // НАЧАЛО тура <= НАЧАЛО фильтра И КОНЕЦ тура >= КОНЕЦ фильтра
        return tourNights[0] <= minNights && tourNights[1] >= maxNights;
      });
    }

    console.log('🎯 ИТОГО:', filtered.length, 'туров');
    return filtered;
  };

  // Загружаем ВСЕ туры один раз
  useEffect(() => {
    fetch('tours.json')
      .then(res => res.json())
      .then(data => {
        console.log('📦 Загружено туров:', data.length);
        console.log('Первый тур:', data[0]); // DEBUG структура
        setAllTours(data);
        setLoading(false);
      })
      .catch(err => {
        console.error('❌ Ошибка:', err);
        setLoading(false);
      });
  }, []);

  // 🔥 ФИЛЬТРУЕМ при изменении URL
  useEffect(() => {
    if (allTours.length > 0) {
      const filtered = filterTours(allTours);
      setTours(filtered);
    }
  }, [searchParams, allTours]);

  if (loading) {
    return (
      <div className="TVSearchResults" style={{ margin: "0 auto", width: "1296px" }}>
        <div style={{ padding: '40px', textAlign: 'center', color: '#666' }}>
          Загрузка туров...
        </div>
      </div>
    );
  }

  return (
    <>
      <div className="TVSearchResults" style={{ margin: "0 auto", width: "1296px" }}>
        <div className="TVResultContentListWrapper">
          <div className="TVResultListView TVStyleTheme2">
            <div className="TVResultListViewBody TVResultContentList">
              
              {/* DEBUG ИНФО */}
              <div style={{ 
                padding: '20px', 
                background: '#f8f9fa', 
                marginBottom: '20px',
                borderRadius: '8px',
                fontSize: '14px'
              }}>
                <strong>🎯 Найдено: {tours.length} / {allTours.length}</strong>
                <br />
                <small>
                  Страна: "{decodeURIComponent(searchParams.get('country') || 'все')}" | 
                  Вылет: "{decodeURIComponent(searchParams.get('departure') || 'все')}"
                </small>
              </div>

              <div className="TVResultListViewList" id="tour-container">
                {tours.length === 0 ? (
                  <div style={{ 
                    padding: '60px 20px', 
                    textAlign: 'center', 
                    color: '#666',
                    fontSize: '18px'
                  }}>
                    ❌ Ничего не найдено
                    <br />
                    <small>F12 → Console → смотри логи 🔍</small>
                  </div>
                ) : (
                  tours.map((tour) => (
                    <div key={tour.id} className="TVResultListViewItem">
                      <div className="TVHotelResultItem">
                        <div className="TVHotelResulItemInfo">
                          <div className="TVHotelInfo">
                            <div className="TVResultItem">
                              <div className="TVResultItemImageWrapper TVSize-M">
                                <div className="TVResultItemImage">
                                  <div className="TVGallery TVResultItemGallery">
                                    <div className="TVGallContainer">
                                      <div className="TVGallList" style={{ width: "100%" }}>
                                        <div
                                          className="TVPhotoGalleryImage"
                                          style={{
                                            backgroundImage: `url('https://picsum.photos/400/200?random=${tour.id}')`,
                                            backgroundSize: "cover",
                                            height: "200px",
                                          }}
                                        />
                                      </div>
                                    </div>
                                  </div>
                                </div>
                              </div>
                              
                              <div className="TVResultItemBodyWrapper TVResultItemBodyWrapperStretched">
                                <div className="TVResultItemHeader">
                                  {/* ⭐ ЗВЕЗДЫ */}
                                  <div className="TVResultItemPreTitle">
                                    <div className="stars-row">
                                      {[...Array(tour.stars)].map((_, i) => (
                                        <div key={i} className="TVHotelInfoStar TVColorYellow500">★</div>
                                      ))}
                                    </div>
                                  </div>
                                  
                                  {/* 🏨 НАЗВАНИЕ */}
                                  <div className="TVResultItemTitle">
                                    <Link className="TVHotelInfoTitleLink" to={`/tour/${tour.id}`}>
                                      {tour.title}
                                    </Link>
                                  </div>
                                  
                                  {/* 📍 ЛОКАЦИЯ */}
                                  <div className="TVResultItemSubTitle">
                                    {tour.city}, {tour.country} | {tour.departureCity}
                                  </div>
                                  
                                  {/* 📅 ДАТЫ + НОЧИ */}
                                  <div style={{ color: '#666', fontSize: '14px', margin: '5px 0' }}>
                                    {tour.dates} | {tour.nights} ночей
                                  </div>
                                  
                                  {/* 💰 ЦЕНА */}
                                  <div className="TVResultItemPrice">
                                    <div className="TVResultItemNewPrice" style={{ 
                                      fontSize: '24px', 
                                      fontWeight: 'bold', 
                                      color: '#c50076' 
                                    }}>
                                      {tour.price.toLocaleString()} ₽
                                    </div>
                                  </div>
                                </div>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      <style jsx>{`
        .TVHide { display: none !important; }
        .TVResultNavButton {
          display: inline-block;
          padding: 5px 10px;
          margin-right: 5px;
          background: #eee;
          border-radius: 4px;
          cursor: pointer;
          text-decoration: none;
          color: #333;
        }
        .TVResultNavButton:hover { background: #ddd; }
        .stars-row { display: flex; gap: 2px; }
        .TVHotelInfoStar { color: #ffc107; font-size: 16px; }
      `}</style>
    </>
  );
};

export default SearchResults;
